# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib3
import base64

http = urllib3.PoolManager()

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    enriched_data = {}
    
    # Check for X-Enrich-URL headers
    enrich_urls = []
    for header_name, header_values in headers.items():
        if header_name.lower().startswith('x-enrich-url'):
            for header_value in header_values:
                enrich_urls.append(header_value['value'])
    
    # Fetch data from each URL
    for url in enrich_urls:
        try:
            response = http.request('GET', url, timeout=2.0, retries=False)
            if response.status == 200:
                data = response.data.decode('utf-8')
                try:
                    enriched_data[url] = json.loads(data)
                except json.JSONDecodeError:
                    enriched_data[url] = data
        except Exception as e:
            enriched_data[url] = {'error': str(e)}
    
    # Add enriched data to request headers as base64 encoded JSON
    if enriched_data:
        enriched_json = json.dumps(enriched_data)
        enriched_b64 = base64.b64encode(enriched_json.encode('utf-8')).decode('utf-8')
        
        # CloudFront header value size limit is 1783 bytes per header
        # Split if necessary
        max_chunk_size = 1700
        chunks = [enriched_b64[i:i+max_chunk_size] for i in range(0, len(enriched_b64), max_chunk_size)]
        
        for idx, chunk in enumerate(chunks):
            header_name = f'x-enriched-data-{idx}'
            headers[header_name] = [{
                'key': header_name,
                'value': chunk
            }]
    
    return request